export interface CoverProps {
  title: string;
  subtitle?: string;
  accent: string;
  imageUrl?: string;
  dual?: boolean;
  logoStyle?: "auto" | "box" | "lettermark" | "full";
  showSub?: boolean;
  showLogo?: boolean;
  showMeta?: boolean;
  upper?: boolean;
  tight?: boolean;
}

export type CoverTemplateId = "01" | "02" | "03" | "04" | "05" | "06";

export interface CoverTemplate {
  id: CoverTemplateId;
  name: string;
  preferredLogo: "box" | "lettermark" | "full";
  supportsDual: boolean;
  render: (props: CoverProps) => string;
}

export const COVER_W = 1080;
export const COVER_H = 1350;

const W = COVER_W;
const H = COVER_H;

interface ResolvedCoverProps {
  title: string;
  subtitle: string;
  accent: string;
  imageUrl: string;
  dual: boolean;
  logoStyle: "auto" | "box" | "lettermark" | "full";
  showSub: boolean;
  showLogo: boolean;
  showMeta: boolean;
  upper: boolean;
  tight: boolean;
}

function resolve(p: CoverProps): ResolvedCoverProps {
  return {
    title: p.title,
    subtitle: p.subtitle || "",
    accent: p.accent || "#F7B041",
    imageUrl: p.imageUrl || "",
    dual: p.dual || false,
    logoStyle: p.logoStyle || "auto",
    showSub: p.showSub !== false,
    showLogo: p.showLogo !== false,
    showMeta: p.showMeta !== false,
    upper: p.upper !== false,
    tight: p.tight || false,
  };
}

