function esc(s: string): string {
  return String(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
}

function displayTitle(p: ResolvedCoverProps): string {
  return p.upper ? p.title.toUpperCase() : p.title;
}

function tracking(p: ResolvedCoverProps): string {
  return p.tight ? "-2.5" : "-1";
}

function wordWrap(text: string, maxCharsPerLine: number): string[] {
  const words = text.split(/\s+/);
  const lines: string[] = [];
  let cur = "";
  for (const w of words) {
    if ((cur + " " + w).trim().length <= maxCharsPerLine) {
      cur = (cur + " " + w).trim();
    } else {
      if (cur) lines.push(cur);
      cur = w;
    }
  }
  if (cur) lines.push(cur);
  return lines;
}

function titleFontSizeForLines(lines: string[], baseSize: number, maxWidth: number): number {
  if (!lines.length) return baseSize;
  const maxLen = lines.reduce((m, l) => Math.max(m, l.length), 0);
  const perChar = 0.58;
  const fitSize = Math.floor(maxWidth / (maxLen * perChar));
  return Math.max(44, Math.min(baseSize, fitSize));
}

interface TitleBlockResult {
  svg: string;
  topY: number;
  bottomY: number;
}

function titleBlock(
  p: ResolvedCoverProps,
  lines: string[],
  fs: number,
  x: number,
  bottomBaselineY: number,
  fill: string = "#FFFFFF",
  anchor: "start" | "middle" = "start"
): TitleBlockResult {
  const lineGap = fs * 1.02;
  const topBaselineY = bottomBaselineY - (lines.length - 1) * lineGap;
  const tx = anchor === "middle" ? `text-anchor="middle"` : "";
  const trk = tracking(p);
  const svg = lines.map((ln, i) =>
    `<text x="${x}" y="${topBaselineY + i * lineGap}" font-family="'Outfit', sans-serif" font-size="${fs}" font-weight="900" letter-spacing="${trk}" fill="${fill}" ${tx}>${esc(ln)}</text>`
  ).join("");
  return { svg, topY: topBaselineY - fs, bottomY: bottomBaselineY };
}

function gradient(id: string, stops: { o: string; c: string; a: number }[]): string {
  return `<linearGradient id="${id}" x1="0%" y1="0%" x2="0%" y2="100%">${stops.map(s => `<stop offset="${s.o}" stop-color="${s.c}" stop-opacity="${s.a}"/>`).join("")}</linearGradient>`;
}

function imageOrFallback(p: ResolvedCoverProps, id: string): string {
  if (p.imageUrl) {
    return `<image href="${esc(p.imageUrl)}" x="0" y="0" width="${W}" height="${H}" preserveAspectRatio="xMidYMid slice"/>`;
  }
  return `
    <defs>
      <linearGradient id="${id}-fb" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stop-color="#1A2438"/>
        <stop offset="55%" stop-color="#0B1322"/>
        <stop offset="100%" stop-color="#000000"/>
      </linearGradient>
      <pattern id="${id}-pat" width="40" height="46" patternUnits="userSpaceOnUse" patternTransform="rotate(0)">
        <polygon points="12,2 28,2 38,12 38,34 28,44 12,44 2,34 2,12" fill="none" stroke="${p.accent}" stroke-opacity="0.04" stroke-width="1"/>
      </pattern>
    </defs>
    <rect width="${W}" height="${H}" fill="url(#${id}-fb)"/>
    <rect width="${W}" height="${H}" fill="url(#${id}-pat)"/>
  `;
}

function dropShadowDefs(id: string): string {
  return `<defs><filter id="${id}" x="-20%" y="-20%" width="140%" height="140%">
    <feDropShadow dx="0" dy="2" stdDeviation="8" flood-color="#000000" flood-opacity="0.85"/>
  </filter></defs>`;
}

function shadowed(id: string, inner: string): string {
  return `<g filter="url(#${id})">${inner}</g>`;
}

function metaTag(p: ResolvedCoverProps, text: string, x: number, y: number, fill: string = "rgba(255,255,255,0.85)"): string {
  if (!p.showMeta) return "";
  return `<text x="${x}" y="${y}" font-family="'JetBrains Mono', monospace" font-size="20" font-weight="700" letter-spacing="3" fill="${fill}">${esc(text)}</text>`;
}

function subtitleBlock(p: ResolvedCoverProps, text: string, x: number, y: number, maxWidth: number, fill: string = "rgba(255,255,255,0.78)"): string {
  if (!p.showSub || !text) return "";
  const lines = wordWrap(text, Math.floor(maxWidth / 16));
  return lines.map((ln, i) => `<text x="${x}" y="${y + i * 38}" font-family="'Outfit', sans-serif" font-size="30" font-weight="400" fill="${fill}">${esc(ln)}</text>`).join("");
}

function saMark(p: ResolvedCoverProps, x: number, y: number, w: number, h: number, preferred: "box" | "lettermark" | "full"): string {
  if (!p.showLogo) return "";
  const style: "box" | "lettermark" | "full" = p.logoStyle === "auto" ? preferred : p.logoStyle;
  let inner: string;
  let vbW: number;
  let vbH: number;
  if (style === "box") {
    inner = LOGO_BOX_INNER;
    vbW = LOGO_BOX_VBW;
    vbH = LOGO_BOX_VBH;
  } else if (style === "lettermark") {
    inner = LOGO_LETTERMARK_INNER;
    vbW = LOGO_LETTERMARK_VBW;
    vbH = LOGO_LETTERMARK_VBH;
  } else {
    inner = LOGO_FULL_INNER;
    vbW = LOGO_FULL_VBW;
    vbH = LOGO_FULL_VBH;
  }
  const scaleX = w / vbW;
  const scaleY = h / vbH;
  const scale = Math.min(scaleX, scaleY);
  const actualW = vbW * scale;
  const actualH = vbH * scale;
  return `<g transform="translate(${x + (w - actualW)}, ${y + (h - actualH) / 2}) scale(${scale})">${inner}</g>`;
}

// Suppress unused-warning for helpers exposed for potential future covers.
void titleFontSizeForLines;

function render01(rawP: CoverProps): string {
  const p = resolve(rawP);
  const t = displayTitle(p);
  const pad = 60;
  const frameW = W - pad * 2;
  const frameH = H - pad * 2;
  const innerPad = 24;
  const textX = pad + innerPad;
  const maxTitleWidth = frameW - innerPad * 2;
  const subWrap = Math.max(20, Math.floor(maxTitleWidth / 17));
  const titleWrap = Math.max(8, Math.floor(maxTitleWidth / 28));
  const lines = wordWrap(t, titleWrap);
  const fs = titleFontSizeForLines(lines, 110, maxTitleWidth);

  const subLines = p.showSub && p.subtitle ? wordWrap(p.subtitle, subWrap) : [];
  const subFs = 30;
  const subGap = 36;

  const frameBottom = pad + frameH;
  const blockBottomMargin = 70;
  const subBottomY = frameBottom - blockBottomMargin;
  const subStartY = subBottomY - (subLines.length - 1) * subGap;
  const titleBottomY = subLines.length ? subStartY - 70 : subBottomY;
  const tb = titleBlock(p, lines, fs, textX, titleBottomY);

  const innerImage = p.imageUrl
    ? `<image href="${esc(p.imageUrl)}" x="${pad}" y="${pad}" width="${frameW}" height="${frameH}" preserveAspectRatio="xMidYMid slice"/>`
    : `<rect x="${pad}" y="${pad}" width="${frameW}" height="${frameH}" fill="#0F1626"/>
       <rect x="${pad}" y="${pad}" width="${frameW}" height="${frameH}" fill="url(#v01-pat-inner)"/>`;

  return `
    <defs>
      <pattern id="v01-pat-outer" width="40" height="46" patternUnits="userSpaceOnUse">
        <polygon points="12,2 28,2 38,12 38,34 28,44 12,44 2,34 2,12" fill="none" stroke="${p.accent}" stroke-opacity="0.11" stroke-width="1"/>
      </pattern>
      <pattern id="v01-pat-inner" width="40" height="46" patternUnits="userSpaceOnUse">
        <polygon points="12,2 28,2 38,12 38,34 28,44 12,44 2,34 2,12" fill="none" stroke="${p.accent}" stroke-opacity="0.07" stroke-width="1"/>
      </pattern>
      <clipPath id="v01-frame"><rect x="${pad}" y="${pad}" width="${frameW}" height="${frameH}"/></clipPath>
      ${gradient("v01-grad", [{o:"0%",c:"#000",a:0},{o:"45%",c:"#000",a:0},{o:"100%",c:"#000",a:0.94}])}
    </defs>
    <rect width="${W}" height="${H}" fill="#0A0B10"/>
    <rect width="${W}" height="${H}" fill="url(#v01-pat-outer)"/>
    <g clip-path="url(#v01-frame)">
      ${innerImage}
      <rect x="${pad}" y="${pad}" width="${frameW}" height="${frameH}" fill="url(#v01-grad)"/>
      ${tb.svg}
      ${subLines.map((ln, i) => `<text x="${textX}" y="${subStartY + i * subGap}" font-family="'Outfit', sans-serif" font-size="${subFs}" font-weight="400" fill="rgba(255,255,255,0.88)">${esc(ln)}</text>`).join("")}
    </g>
    <rect x="${pad}" y="${pad}" width="${frameW}" height="${frameH}" fill="none" stroke="#FFFFFF" stroke-opacity="0.20" stroke-width="2"/>
    ${dropShadowDefs("v01-shadow")}
    ${shadowed("v01-shadow", saMark(p, W - pad - 220 - innerPad, pad + innerPad, 220, 132, "box"))}
  `;
}

function render02(rawP: CoverProps): string {
  const p = resolve(rawP);
  const t = displayTitle(p);
  const pad = 80;
  const maxWidth = W - pad * 2;
  const lines = wordWrap(t, 9);
  const fs = titleFontSizeForLines(lines, 170, maxWidth);
  const lineGap = fs * 1.0;
  const titleStartY = 260 + fs;

  const subLines = p.showSub && p.subtitle ? wordWrap(p.subtitle, 40) : [];
  const subFs = 30;
  const subGap = 36;
  const subEndY = H - 130;
  const subStartY = subEndY - (subLines.length - 1) * subGap;

  const bg = p.imageUrl
    ? `<image href="${esc(p.imageUrl)}" x="0" y="0" width="${W}" height="${H}" preserveAspectRatio="xMidYMid slice"/>
       <rect width="${W}" height="${H}" fill="#0A0B10" fill-opacity="0.74"/>
       <rect width="${W}" height="${H}" fill="url(#v02-pat)"/>`
    : `<rect width="${W}" height="${H}" fill="#0A0B10"/>
       <rect width="${W}" height="${H}" fill="url(#v02-pat)"/>`;

  const trk = tracking(p);

  return `
    <defs>
      <pattern id="v02-pat" width="44" height="50" patternUnits="userSpaceOnUse">
        <polygon points="13,2 31,2 42,13 42,37 31,48 13,48 2,37 2,13" fill="none" stroke="${p.accent}" stroke-opacity="0.07" stroke-width="1"/>
      </pattern>
    </defs>
    ${bg}
    <rect x="0" y="0" width="${W}" height="14" fill="${p.accent}"/>
    ${lines.map((ln, i) => `<text x="${pad}" y="${titleStartY + i * lineGap}" font-family="'Outfit', sans-serif" font-size="${fs}" font-weight="900" letter-spacing="${trk}" fill="#FFFFFF">${esc(ln)}</text>`).join("")}
    <line x1="${pad}" y1="${subStartY - 80}" x2="${pad + 100}" y2="${subStartY - 80}" stroke="${p.accent}" stroke-width="4"/>
    ${subLines.map((ln, i) => `<text x="${pad}" y="${subStartY + i * subGap}" font-family="'Outfit', sans-serif" font-size="${subFs}" font-weight="400" fill="rgba(255,255,255,0.80)">${esc(ln)}</text>`).join("")}
    ${metaTag(p, "TEAR-DOWN · SEMIANALYSIS", pad, H - 60, "rgba(255,255,255,0.4)")}
    ${saMark(p, W - 80 - 240, H - 200, 240, 120, "lettermark")}
  `;
}

function render03(rawP: CoverProps): string {
  const p = resolve(rawP);
  const t = displayTitle(p);
  const pad = 60;
  const maxTitleWidth = W - pad * 2 - 48;
  const lines = wordWrap(t, 20);
  const fs = titleFontSizeForLines(lines, 100, maxTitleWidth);

  const subLines = p.showSub && p.subtitle ? wordWrap(p.subtitle, 44) : [];
  const subFs = 30;
  const subGap = 36;
  const subEndY = H - 110;
  const subStartY = subEndY - (subLines.length - 1) * subGap;
  const titleBottomY = subLines.length ? subStartY - 70 : subEndY;
  const tb = titleBlock(p, lines, fs, pad + 24, titleBottomY);

  const dual = p.dual;
  const splitY = H / 2;

  const filterDef = `
    <defs>
      <filter id="v03-tint" x="0" y="0" width="100%" height="100%">
        <feColorMatrix type="matrix" values="
          0.30 0.59 0.11 0 0
          0.30 0.59 0.11 0 0
          0.30 0.59 0.11 0 0
          0    0    0    1 0"/>
        <feComponentTransfer>
          <feFuncR type="table" tableValues="0 1"/>
          <feFuncG type="table" tableValues="0 0.72"/>
          <feFuncB type="table" tableValues="0 0.30"/>
        </feComponentTransfer>
      </filter>
      <clipPath id="v03-top"><rect x="0" y="0" width="${W}" height="${splitY}"/></clipPath>
      <clipPath id="v03-bot"><rect x="0" y="${splitY}" width="${W}" height="${H - splitY}"/></clipPath>
      ${gradient("v03-grad", [{o:"0%",c:"#000",a:0},{o:"55%",c:"#000",a:0},{o:"100%",c:"#000",a:0.94}])}
    </defs>
  `;

  const dualImg = p.imageUrl
    ? `
      <g clip-path="url(#v03-top)">
        <image href="${esc(p.imageUrl)}" x="0" y="0" width="${W}" height="${H}" preserveAspectRatio="xMidYMid slice"/>
      </g>
      <g clip-path="url(#v03-bot)" filter="url(#v03-tint)">
        <image href="${esc(p.imageUrl)}" x="0" y="0" width="${W}" height="${H}" preserveAspectRatio="xMidYMid slice"/>
      </g>
    `
    : `
      <rect x="0" y="0" width="${W}" height="${splitY}" fill="#1A2438"/>
      <rect x="0" y="${splitY}" width="${W}" height="${H - splitY}" fill="#0F2230"/>
    `;

  const singleImg = imageOrFallback(p, "v03");

  return `
    ${filterDef}
    ${dual ? dualImg : singleImg}
    ${dual ? `<line x1="0" y1="${splitY}" x2="${W}" y2="${splitY}" stroke="${p.accent}" stroke-width="4"/>` : ""}
    <rect width="${W}" height="${H}" fill="url(#v03-grad)"/>
    ${dropShadowDefs("v03-shadow")}
    ${shadowed("v03-shadow", saMark(p, W - 60 - 220, 50, 220, 132, "full") + metaTag(p, dual ? "DIPTYCH · 06 / 26" : "INFRASTRUCTURE · 06 / 26", 60, 95, p.accent))}
    ${tb.svg}
    ${subLines.map((ln, i) => `<text x="${pad + 24}" y="${subStartY + i * subGap}" font-family="'Outfit', sans-serif" font-size="${subFs}" font-weight="400" fill="rgba(255,255,255,0.82)">${esc(ln)}</text>`).join("")}
  `;
}

function render04(rawP: CoverProps): string {
  const p = resolve(rawP);
  const t = displayTitle(p);
  const pad = 60;
  const maxTitleWidth = W - pad - 80;
  const lines = wordWrap(t, 20);
  const fs = titleFontSizeForLines(lines, 100, maxTitleWidth);

  const subLines = p.showSub && p.subtitle ? wordWrap(p.subtitle, 44) : [];
  const subFs = 30;
  const subGap = 36;
  const subEndY = H - 100;
  const subStartY = subEndY - (subLines.length - 1) * subGap;
  const titleBottomY = subLines.length ? subStartY - 70 : subEndY;
  const tb = titleBlock(p, lines, fs, pad, titleBottomY);

  return `
    ${imageOrFallback(p, "v04")}
    <rect x="0" y="0" width="16" height="${H}" fill="${p.accent}"/>
    <defs>${gradient("v04-grad", [{o:"0%",c:"#000",a:0.15},{o:"45%",c:"#000",a:0},{o:"100%",c:"#000",a:0.94}])}</defs>
    <rect width="${W}" height="${H}" fill="url(#v04-grad)"/>
    ${dropShadowDefs("v04-shadow")}
    ${shadowed("v04-shadow", metaTag(p, "06 / 2026 · INFRA", W - 360, 90, p.accent) + saMark(p, W - 60 - 160, 130, 160, 180, "box"))}
    ${tb.svg}
    ${subLines.map((ln, i) => `<text x="${pad}" y="${subStartY + i * subGap}" font-family="'Outfit', sans-serif" font-size="${subFs}" font-weight="400" fill="rgba(255,255,255,0.82)">${esc(ln)}</text>`).join("")}
  `;
}

function render05(rawP: CoverProps): string {
  const p = resolve(rawP);
  const t = displayTitle(p);
  const pad = 60;
  const imgH = Math.round(H * 0.62);
  const maxTitleWidth = W - pad * 2;
  const lines = wordWrap(t, 22);
  const fs = titleFontSizeForLines(lines, 90, maxTitleWidth);

  const subLines = p.showSub && p.subtitle ? wordWrap(p.subtitle, 50) : [];
  const subFs = 26;
  const subGap = 32;

  const barTop = imgH;
  const barH = H - imgH;
  const metaY = barTop + 56;
  const titleTopBaselineY = barTop + 130;
  const titleLineGap = fs * 1.02;
  const titleBottomY = titleTopBaselineY + (lines.length - 1) * titleLineGap;
  const subStartY = titleBottomY + 60;
  const trk = tracking(p);

  return `
    <rect width="${W}" height="${H}" fill="#0A0B10"/>
    <g clip-path="url(#v05-clip)">
      ${p.imageUrl
        ? `<image href="${esc(p.imageUrl)}" x="0" y="0" width="${W}" height="${imgH}" preserveAspectRatio="xMidYMid slice"/>`
        : `<rect width="${W}" height="${imgH}" fill="#1A2438"/>`}
    </g>
    <defs><clipPath id="v05-clip"><rect width="${W}" height="${imgH}"/></clipPath></defs>
    <rect x="0" y="${barTop}" width="${W}" height="${barH}" fill="#0A0B10"/>
    <rect x="0" y="${barTop}" width="${W}" height="6" fill="${p.accent}"/>
    ${dropShadowDefs("v05-shadow")}
    ${shadowed("v05-shadow", saMark(p, W - 60 - 240, 50, 240, 100, "lettermark"))}
    ${metaTag(p, "ISSUE 24 · INFRASTRUCTURE", pad, metaY, p.accent)}
    ${lines.map((ln, i) => `<text x="${pad}" y="${titleTopBaselineY + i * titleLineGap}" font-family="'Outfit', sans-serif" font-size="${fs}" font-weight="900" letter-spacing="${trk}" fill="#FFFFFF">${esc(ln)}</text>`).join("")}
    ${subLines.map((ln, i) => `<text x="${pad}" y="${subStartY + i * subGap}" font-family="'Outfit', sans-serif" font-size="${subFs}" font-weight="400" fill="rgba(255,255,255,0.72)">${esc(ln)}</text>`).join("")}
  `;
}

function render06(rawP: CoverProps): string {
  const p = resolve(rawP);
  const t = displayTitle(p);
  const pad = 60;
  const maxTitleWidth = W - pad * 2;
  const lines = wordWrap(t, 18);
  const fs = titleFontSizeForLines(lines, 110, maxTitleWidth);

  const subLines = p.showSub && p.subtitle ? wordWrap(p.subtitle, 44) : [];
  const subFs = 30;
  const subGap = 36;
  const subEndY = H - 110;
  const subStartY = subEndY - (subLines.length - 1) * subGap;
  const titleBottomY = subLines.length ? subStartY - 70 : subEndY;
  const tb = titleBlock(p, lines, fs, pad, titleBottomY);

  return `
    ${imageOrFallback(p, "v06")}
    <rect x="0" y="0" width="${W}" height="22" fill="${p.accent}"/>
    <defs>${gradient("v06-grad", [{o:"0%",c:"#000",a:0.18},{o:"45%",c:"#000",a:0},{o:"100%",c:"#000",a:0.93}])}</defs>
    <rect width="${W}" height="${H}" fill="url(#v06-grad)"/>
    ${dropShadowDefs("v06-shadow")}
    ${shadowed("v06-shadow", metaTag(p, "YB · 04 · INFRASTRUCTURE", pad, 100, "#FFFFFF") + saMark(p, W - 60 - 160, 70, 160, 180, "box"))}
    <rect x="${pad}" y="${titleBottomY - fs - 60}" width="68" height="4" fill="${p.accent}"/>
    ${tb.svg}
    ${subLines.map((ln, i) => `<text x="${pad}" y="${subStartY + i * subGap}" font-family="'Outfit', sans-serif" font-size="${subFs}" font-weight="400" fill="rgba(255,255,255,0.82)">${esc(ln)}</text>`).join("")}
  `;
}

// Currently unused helper, exported via subtitleBlock-style API parity for future cover variants.
void subtitleBlock;

export const COVER_TEMPLATES: CoverTemplate[] = [
  { id: "01", name: "Reference",   preferredLogo: "box",        supportsDual: false, render: render01 },
  { id: "02", name: "Type Bomb",   preferredLogo: "lettermark", supportsDual: false, render: render02 },
  { id: "03", name: "Diptych",     preferredLogo: "full",       supportsDual: true,  render: render03 },
  { id: "04", name: "Accent Rail", preferredLogo: "box",        supportsDual: false, render: render04 },
  { id: "05", name: "Magazine Bar",preferredLogo: "lettermark", supportsDual: false, render: render05 },
  { id: "06", name: "Edge Stripe", preferredLogo: "box",        supportsDual: false, render: render06 },
];

export function renderCoverSvg(id: CoverTemplateId, props: CoverProps): string {
  const tpl = COVER_TEMPLATES.find(t => t.id === id);
  if (!tpl) throw new Error(`Unknown cover template: ${id}`);
  return tpl.render(props);
}

export function renderCoverFullSvg(id: CoverTemplateId, props: CoverProps): string {
  const inner = renderCoverSvg(id, props);
  return `<svg viewBox="0 0 ${COVER_W} ${COVER_H}" xmlns="http://www.w3.org/2000/svg">${inner}</svg>`;
}
